import{_ as t,o as a,c as s,a2 as o}from"./chunks/framework.DnrXFDHb.js";const m=JSON.parse('{"title":"FAQ & Troubleshooting","description":"","frontmatter":{},"headers":[],"relativePath":"faq.md","filePath":"faq.md"}'),i={name:"faq.md"};function r(l,e,n,c,d,u){return a(),s("div",null,[...e[0]||(e[0]=[o('<h1 id="faq-troubleshooting" tabindex="-1"><i class="ph ph-question"></i> FAQ &amp; Troubleshooting <a class="header-anchor" href="#faq-troubleshooting" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-question&quot;&gt;&lt;/i&gt; FAQ &amp; Troubleshooting&quot;">​</a></h1><p>This section compiles answers to the most frequent questions and solutions for typical issues encountered during WebGL optimization.</p><h2 id="installation-and-demo-scene" tabindex="-1"><i class="ph ph-package"></i> Installation and Demo Scene <a class="header-anchor" href="#installation-and-demo-scene" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-package&quot;&gt;&lt;/i&gt; Installation and Demo Scene&quot;">​</a></h2><details class="details custom-block"><summary>Q: I opened the demo scene, but all materials and objects are pink!</summary><p><strong>A:</strong> Your project utilizes URP, while the demo scene is configured by default for BiRP. Simply unpack the package located at <code>WebAdaptivePerformance/Demo/Import Me (URP).unitypackage</code>. The shaders will update automatically.</p></details><details class="details custom-block"><summary>Q: I installed the plugin, but visually, absolutely nothing changes in the game.</summary><p><strong>A:</strong> Review this checklist:</p><ul><li>Is the plugin enabled in Project Settings? Are the Scalers added and active?</li><li>Are the Unity graphics initially set to maximum? The plugin has nothing to reduce if the settings are already low.</li><li>Your device might just be handling the load effortlessly, and the FPS is stable. Add the <code>Dashboard</code> prefab to the scene to observe the Indexer&#39;s current decisions.</li><li>If everything is configured correctly but there is no effect — reach out to us, and we&#39;ll help you troubleshoot.</li></ul></details><h2 id="resolution-and-user-interface-ui" tabindex="-1"><i class="ph ph-monitor-play"></i> Resolution and User Interface (UI) <a class="header-anchor" href="#resolution-and-user-interface-ui" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-monitor-play&quot;&gt;&lt;/i&gt; Resolution and User Interface (UI)&quot;">​</a></h2><details class="details custom-block"><summary>Q: The resolution is not changing (Resolution Scaler is inactive).</summary><p><strong>A:</strong> The two most common causes:</p><ol><li>If you are using <strong>BiRP</strong> and the <code>RenderTextureScaling</code> mode: inspect the <code>Target Tags</code> array in the Scaler settings. If your game&#39;s camera has a different name (not <code>MainCamera</code>), you must input its tag. Otherwise, the plugin will simply fail to locate it.</li><li>The <code>NativeBrowserScaling</code> mode operates exclusively in a compiled WebGL build. It performs no actions in the Unity Editor.</li></ol></details><details class="details custom-block"><summary>Q: When FPS drops, my UI also becomes blurry!</summary><p><strong>A:</strong> Verify that in BiRP, you selected <code>RenderTextureScaling</code>. The Canvas itself must be set to <code>Screen Space - Overlay</code> mode (or utilize a dedicated UI camera).</p></details><details class="details custom-block"><summary>Q: Standard UI buttons work perfectly, but my custom mouse clicks on 3D objects are off-target.</summary><p><strong>A:</strong> Standard EventSystem events are automatically repaired by our <code>WebScaledPhysicsRaycaster</code> component. However, if you are executing a custom raycast via code (<code>Camera.ScreenPointToRay()</code>), it will miss the target due to the texture size alteration. Utilize the plugin&#39;s dedicated method: <code>WebRaycasterUtility.TryComputeScaledRay()</code>.</p></details><h2 id="metrics-and-system-behavior" tabindex="-1"><i class="ph ph-chart-line-up"></i> Metrics and System Behavior <a class="header-anchor" href="#metrics-and-system-behavior" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-chart-line-up&quot;&gt;&lt;/i&gt; Metrics and System Behavior&quot;">​</a></h2><details class="details custom-block"><summary>Q: Graphics quality dropped due to lag. Now FPS is high again, but the graphics aren&#39;t recovering!</summary><p><strong>A:</strong> The <strong>Anti Yo-Yo Penalty System</strong> has likely triggered. The plugin temporarily blocked the upgrade to prevent Quality flickering.</p><ul><li>If you want the graphics to recover faster, decrease the <code>Penalty Lockout Duration</code> parameter (e.g., to 10 seconds).</li><li>Also, check the <code>Increase Cooldown</code> parameter — the wait time might be set too high.</li></ul></details><details class="details custom-block"><summary>Q: The Dashboard constantly displays a CPU Bottleneck or Unknown, even though the scene is empty.</summary><p><strong>A:</strong> Ensure you enable <code>Frame Timing Stats</code> in Player Settings. Additionally, verify that <code>Application.targetFrameRate = -1</code>. Removing the hard frame limit liberates the metrics from artificial <code>setTimeout</code> delays within the browser.</p></details><details class="details custom-block"><summary>Q: The character or physics objects start stuttering during severe lag spikes.</summary><p><strong>A:</strong> This is a side effect of the <code>Physics Step Scaler</code>. It modifies <code>Time.fixedDeltaTime</code> to rescue the processor from overload. To ensure movement remains visually smooth, enable the <code>Interpolate</code> mode on your character&#39;s <code>Rigidbody</code> component.</p></details><details class="details custom-block"><summary>Q: Shadow Scalers are enabled, but performance isn&#39;t increasing, and the shadows are still present.</summary><p><strong>A:</strong> The plugin exclusively manages dynamic (Realtime) shadows. If the lighting in your scene is Baked/Lightmaps, the Scalers will have absolutely no effect on it.</p></details><h2 id="custom-scalers" tabindex="-1"><i class="ph ph-code"></i> Custom Scalers <a class="header-anchor" href="#custom-scalers" aria-label="Permalink to &quot;&lt;i class=&quot;ph ph-code&quot;&gt;&lt;/i&gt; Custom Scalers&quot;">​</a></h2><details class="details custom-block"><summary>Q: My custom Scaler works perfectly in the Editor but completely disappears in the WebGL build!</summary><p><strong>A:</strong> The IL2CPP compiler stripped it during the build process as &quot;dead code.&quot; Always apply the <code>[UnityEngine.Scripting.Preserve]</code> attribute above your custom Scaler class.</p></details>',16)])])}const p=t(i,[["render",r]]);export{m as __pageData,p as default};
